from typing import Dict, List

class ArticulationPoints:
    def __init__(self, graph: Dict[int, List[int]]):
        self.graph = graph
        self.n = len(graph)
        self.time = 0
        self.low = [-1] * self.n
        self.disc = [-1] * self.n
        self.ap = set()

    def compute(self) -> List[int]:
        for i in range(self.n):
            if self.disc[i] == -1:
                self._dfs(i, -1)
        return sorted(list(self.ap))

    def _dfs(self, u: int, p: int):
        self.disc[u] = self.low[u] = self.time
        self.time += 1
        children = 0
        for v in self.graph[u]:
            if v == p: continue
            if self.disc[v] == -1:
                children += 1
                self._dfs(v, u)
                self.low[u] = min(self.low[u], self.low[v])
                if p != -1 and self.low[v] >= self.disc[u]:
                    self.ap.add(u)
            else:
                self.low[u] = min(self.low[u], self.disc[v])
        if p == -1 and children > 1: self.ap.add(u)

if __name__ == "__main__":
    graph = {0: [1, 2], 1: [0, 2], 2: [0, 1, 3], 3: [2, 4], 4: [3]}
    print(f"APs: {ArticulationPoints(graph).compute()}")
